# Cache invalidation functions
def invalidate_user_cache(user_id=None):
    try:
        if user_id:
            cache_key = generate_cache_key('user', 'get_user_by_id', user_id)
            memcache_client.delete(cache_key)
        
        cache_key = generate_cache_key('users', 'get_all_users')
        memcache_client.delete(cache_key)
    except Exception as e:
        app.logger.error(f"Cache invalidation error: {e}")

